// And groups predicates with the AND operator between them.
func And(predicates ...predicate.CompetitionEntry) predicate.CompetitionEntry {
	return predicate.CompetitionEntry(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.CompetitionEntry) predicate.CompetitionEntry {
	return predicate.CompetitionEntry(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.CompetitionEntry) predicate.CompetitionEntry {
	return predicate.CompetitionEntry(sql.NotPredicates(p))
}
